import React, { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import styles from "./button-lang.module.css";

interface ButtonLangProps {
  lang: string;
  isActive: boolean;
}

const ButtonLang: React.FC<ButtonLangProps> = ({ lang, isActive }) => {
  const { i18n } = useTranslation();
  const [activeLanguage, setActiveLanguage] = useState<string>(
    localStorage.getItem("selectedLanguage") || lang
  );

  // Define a toggle function to switch the active language
  const toggleLanguage = () => {
    const newLanguage = activeLanguage === "en" ? "es" : "en"; // Toggle between "en" and "es"
    i18n.changeLanguage(newLanguage);
    setActiveLanguage(newLanguage);
    localStorage.setItem("selectedLanguage", newLanguage); // Save selected language to localStorage
  };

  useEffect(() => {
    // Update the language when the component mounts
    i18n.changeLanguage(activeLanguage);
  }, [i18n, activeLanguage]);

  useEffect(() => {
    // Update the activeLanguage state when the isActive prop changes
    if (isActive) {
      setActiveLanguage(lang);
    }
  }, [isActive, lang]);

  return (
    <button
      className={`${styles.btn_lang} ${isActive ? styles.btn_active : ""}`}
      onClick={toggleLanguage} // Use the toggle function
    >
      {lang.toUpperCase()}
    </button>
  );
};

export default ButtonLang;
